+    use coding_agent_search::search::two_tier_search::normalize_scores;
+
+    // Test basic normalization
+    let scores = vec![0.8, 0.6, 0.4, 0.2];
+    let normalized = normalize_scores(&scores);
+
+    assert!(
+        (normalized[0] - 1.0).abs() < 0.001,
